import { useState, useEffect, useCallback } from 'react';

import BaseTamplate from '../../consts/BaseTamplate';
import { readRows } from '../../consts/crud';
import '../../App.css';
import '../../../node_modules/bootstrap/dist/css/bootstrap.css'


function Privilege() {
    const [tableData, setTableData] = useState();
    const [loading, setLoading] = useState(false);

    const fetchTableData = useCallback(async () => {
        setLoading(true);

        const read_priviliges = await readRows('/privileges');
        setTableData(read_priviliges);

        setLoading(false);
    }, []);

    useEffect(() => {
        fetchTableData();
    }, [fetchTableData]);

    return (
        <div> 
            {loading ? 
            (
                <div>
                    <p>Загрузка данных...</p>
                </div>
            ) : tableData?.length > 0 ? 
            (
                <div>
                    <BaseTamplate />
                    <div className='container'>
                        <h1>Привелегии.</h1>
                        <table className='table table-striped'>
                            <thead>
                                <tr>
                                    <th scope='col'>ID</th>
                                    <th scope='col'>Пивелегия</th>
                                </tr>
                            </thead>
                            <tbody>
                                {tableData[0]?.items.map((privilege) =>(
                                    <tr key={privilege.id}>
                                        <th>{privilege.id}</th>
                                        <td>{privilege.name_privilege}</td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                </div>
            ) : (
                <p className='no-data'>Нет данных для отображения</p> 
            )} 
        </div>
    );
}

export default Privilege;
